import styles from "./SoundPlayer.module.scss";
import PropTypes from "prop-types";
import classNames from "classnames";
import React, { PureComponent } from "react";
import { Howl, Howler } from "howler";
import { Buttons } from "../../../../../constants/buttons";
import Button, { buttonStyles } from "../../../../common/components/Button/Button";
import { isMobile, isIE } from "../../../../../../common/constants/user-agent";
import SoundControl from "../SoundControl/SoundControl";

export default class SoundPlayer extends PureComponent {
  static controlStep = SoundControl.defaultProps.max;
  static perFrame = 16;

  static propTypes = {
    src: PropTypes.string.isRequired,
    visible: PropTypes.bool.isRequired,
    startAutoSlideshow: PropTypes.func.isRequired,
    stopAutoSlideshow: PropTypes.func.isRequired,
    lockNavControls: PropTypes.func.isRequired,
    unlockNavControls: PropTypes.func.isRequired,
    onToggleClick: PropTypes.func.isRequired
  };

  timer;
  sound = null;
  state = {
    volume: 0,
    currentTime: 0,
    soundDuration: 0,
    forceVisible: false
  };

  get playing() {
    return this.sound && this.sound.playing();
  }

  componentDidMount() {
    this.updateSound(this.props.src);
  }

  componentWillUnmount() {
    Howler.unload();
  }

  componentWillReceiveProps(nextProps) {
    if (nextProps.src !== this.props.src) {
      this.updateSound(nextProps.src);
    }
  }

  playSound = () => {
    this.sound.play();
    this.updateCurrentTime();
  };

  updateCurrentTime() {
    const { soundDuration } = this.state;
    this.timer = requestAnimationFrame(() => {
      if (this.sound) {
        const seek = this.sound.seek() * SoundPlayer.perFrame || this.state.currentTime;

        this.setState({
          currentTime:
            Math.floor(seek) === Math.floor(soundDuration) ? Math.ceil(seek) : Math.round(seek)
        });
        this.updateCurrentTime();
      }
    });
  }

  stopSound = () => {
    if (this.playing) {
      this.sound.stop();
    }
    this.resetSound();
  };

  pauseSound = () => {
    if (this.playing) {
      this.sound.pause();
    }
    this.resetSound();
  };

  resetSound = () => {
    cancelAnimationFrame(this.timer);
    this.timer = null;
    this.forceUpdate();
  };

  updateSound(src) {
    this.stopSound();

    const { stopAutoSlideshow, startAutoSlideshow } = this.props;

    this.sound = new Howl({
      src: [src],
      onload: () => {
        this.setState({
          volume: this.sound.volume() * SoundPlayer.controlStep,
          currentTime: 0,
          soundDuration: this.sound.duration() * SoundPlayer.perFrame
        });
      },
      onplay: stopAutoSlideshow,
      onpause: startAutoSlideshow,
      onstop: startAutoSlideshow,
      onend: () => {
        this.setState({ currentTime: Math.ceil(this.state.soundDuration) });
        this.stopSound();
        startAutoSlideshow();
      }
    });
  }

  onChangeSoundProgress = currentTime => {
    const { soundDuration } = this.state;
    const playing = this.playing;
    const perFrame = SoundPlayer.perFrame - 1;
    const duration = Math.ceil(soundDuration);

    if (currentTime > this.state.currentTime) {
      currentTime += perFrame;
      if (currentTime > duration) currentTime = duration;
    } else if (currentTime < this.state.currentTime) {
      currentTime -= perFrame;
      if (currentTime < 0) currentTime = 0;
    }

    if (isIE && playing) this.stopSound();
    this.sound.seek(currentTime / SoundPlayer.perFrame);
    this.setState({ currentTime });
    if (isIE && playing && currentTime < duration) this.playSound();
  };

  onChangeVolume = val => {
    this.sound.volume(val / SoundPlayer.controlStep);
    this.setState({
      volume: val
    });
  };

  onFocusButton = () => {
    this.setState({ forceVisible: true });
    this.refs.root.parentNode.scrollTop = 0;
  };

  onBlurButton = () => {
    this.setState({ forceVisible: false });
    this.refs.root.parentNode.scrollTop = 0;
  };

  render() {
    const { visible, lockNavControls, unlockNavControls } = this.props;
    const { volume, currentTime, soundDuration, forceVisible } = this.state;
    const soundBtnId = this.playing ? Buttons.PAUSE : Buttons.PLAY;
    const soundHandler = this.playing ? this.pauseSound : this.playSound;

    // don't add a step for progress otherwise it will not go to the end
    return (
      <div
        ref="root"
        className={classNames(
          styles.container,
          (visible || forceVisible) && styles["container-visible"]
        )}
      >
        <div className={classNames(styles.item, isMobile && styles["item-mobile"])}>
          <Button
            id={soundBtnId}
            className={buttonStyles[soundBtnId]}
            onClick={soundHandler}
            onFocus={this.onFocusButton}
            onBlur={this.onBlurButton}
          />
        </div>
        <div className={classNames(styles.item, isMobile && styles["item-mobile"])}>
          <SoundControl
            type="soundtime"
            max={Math.ceil(soundDuration)}
            value={currentTime}
            lockNavControls={lockNavControls}
            unlockNavControls={unlockNavControls}
            onChange={this.onChangeSoundProgress}
            onFocus={this.onFocusButton}
            onBlur={this.onBlurButton}
            ariaValueText="seconds"
          />
        </div>
        {!isMobile && (
          <div className={styles.item}>
            <SoundControl
              type={volume ? "volume_up" : "volume_off"}
              value={volume}
              lockNavControls={lockNavControls}
              unlockNavControls={unlockNavControls}
              onChange={this.onChangeVolume}
              onFocus={this.onFocusButton}
              onBlur={this.onBlurButton}
              ariaValueText="percents"
            />
          </div>
        )}
        <div className={styles["toggle-wrapper"]} onClick={this.props.onToggleClick}>
          <div className={styles.toggle} />
        </div>
      </div>
    );
  }
}
