import React, { PureComponent } from "react";
import { createPortal, findDOMNode } from "react-dom";

export default class Frame extends PureComponent {
  iframeHead;
  iframeRoot;
  fontLinkInserted = false;

  componentDidMount() {
    this.updateContent();
  }

  componentDidUpdate() {
    this.updateContent();
  }

  get document() {
    return findDOMNode(this).contentDocument;
  }

  updateContent = () => {
    const { head, body } = this.document;

    if (this.iframeHead !== head || this.iframeRoot !== body) {
      this.iframeHead = head;
      this.iframeRoot = body;
      this.iframeRoot.style.margin = "0px";
      this.iframeRoot.style.padding = "0px";
      this.forceUpdate();
    }

    if (!this.fontLinkInserted) {
      this.fontLinkInserted = true;
      const link = document.createElement("link");
      link.setAttribute("rel", "stylesheet");
      link.setAttribute("type", "text/css");
      link.href =
        "https://fonts.googleapis.com/css?family=Abril Fatface|Alegreya|Alegreya Sans|Arsenal|Coda|Comfortaa|Cormorant Garamond|Courgette|Dancing Script|Didact Gothic|Euphemia|Gloria Hallelujah|Indie Flower|Josefin Slab|Londrina Solid|Lora|Nobile|Open Sans|Overpass Mono|Patrick Hand|Philosopher|Playfair Display|PT Mono|PT Sans|PT Serif|Raleway|Roboto|Robot Slab|Ubuntu|Ubuntu Mono|Unkempt|Volkhov";
      head.appendChild(link);

      const liStyle = this.document.createElement("style");
      liStyle.innerHTML = "li { list-style-position: inside; }";
      body.appendChild(liStyle);
    }
  };

  render() {
    const { children, head, ...rest } = this.props;

    return (
      <iframe {...rest} onLoad={this.updateContent} title="frame" allowFullScreen>
        {this.iframeHead && createPortal(head, this.iframeHead)}
        {this.iframeRoot && createPortal(children, this.iframeRoot)}
      </iframe>
    );
  }
}
