import types from "./types";
import { Slideshow } from "../../../../common/constants/activities/slideshow";

export default {
  [types.SHOW_NEXT_CARD](state) {
    let currentCardIndex = state.currentCardIndex;
    let cardsCount = state.cardsCount;

    return {
      ...state,
      currentCardIndex: currentCardIndex === cardsCount - 1 ? 0 : ++currentCardIndex
    };
  },
  [types.SHOW_PREV_CARD](state) {
    let currentCardIndex = state.currentCardIndex;
    let cardsCount = state.cardsCount;

    return {
      ...state,
      currentCardIndex: currentCardIndex === 0 ? --cardsCount : --currentCardIndex
    };
  },
  [types.SWITCH_MODE](state) {
    return {
      ...state,
      mode: state.mode === Slideshow.FRONT_MODE ? Slideshow.BACK_MODE : Slideshow.FRONT_MODE
    };
  },
  [types.SELECT_CARD](state, action) {
    return {
      ...state,
      currentCardIndex: action.item
    };
  }
};
