import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import { LiveMessage, LiveAnnouncer } from "react-aria-live";

export default class AdaHelper extends PureComponent {
  static propTypes = {
    ariaText: PropTypes.string.isRequired
  };

  state = {
    text: this.props.ariaText
  };

  componentWillReceiveProps(nextProps) {
    const { ariaText } = nextProps;

    this.setState({
      text:
        ariaText !== this.state.text
          ? ariaText
          : ariaText === ariaText.trim()
          ? `${ariaText} `
          : ariaText.trim()
    });
  }

  render() {
    const { text } = this.state;

    return (
      <LiveAnnouncer>
        <LiveMessage message={text} aria-live="polite" clearOnUnmount={true} />
      </LiveAnnouncer>
    );
  }
}
