import styles from "./Card.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import classNames from "classnames";
import { Modals } from "../../../../../constants/modals";
import { isMSBrowser, isMobile } from "../../../../../../common/constants/user-agent";
import { Animations } from "../../../../../../common/constants/animations";
import CardContent from "../../../../../../common/components/CardContent/CardContent";
import Frame from "../../../../../../common/components/Frame/Frame";
import { Classes } from "../../../../../../common/constants/classes";
import { Buttons } from "../../../../../constants/buttons";
import Button, { buttonStyles } from "../../../../common/components/Button/Button";
import SoundPlayer from "../SoundPlayer/SoundPlayer";

export default class Card extends PureComponent {
  static propTypes = {
    currentCard: PropTypes.object.isRequired,
    fullscreen: PropTypes.bool.isRequired,
    mobileText: PropTypes.bool.isRequired,
    startAutoSlideshow: PropTypes.func.isRequired,
    stopAutoSlideshow: PropTypes.func.isRequired,
    lockNavControls: PropTypes.func.isRequired,
    unlockNavControls: PropTypes.func.isRequired,
    onLeftArrowClick: PropTypes.func.isRequired,
    onRightArrowClick: PropTypes.func.isRequired,
    showModal: PropTypes.func.isRequired,
    animationClass: PropTypes.string.isRequired
  };

  state = {
    controlsVisible: false,
    forceVisibleArrows: false,
    visiblePreviewImage: false
  };

  onImageClick = e => {
    this.setState({ visiblePreviewImage: true });
    this.props.lockNavControls();
    this.props.showModal(
      {
        type: Modals.IMAGE,
        source: this.props.currentCard.image,
        imageClassName: !isMSBrowser ? Animations.ZOOM_IN : "",
        onCancel: () => {
          this.setState({ visiblePreviewImage: false }, () => {
            this.props.unlockNavControls();
          });
        }
      },
      e
    );
  };

  onClick = () => {
    this.setState({
      controlsVisible: !this.state.controlsVisible
    });
  };

  onCardMouseEnter = () => {
    this.setState({
      controlsVisible: true
    });
  };

  onCardMouseLeave = () => {
    this.setState({
      controlsVisible: false
    });
  };

  onCardMouseMove = () => {
    if (this.viewImg) {
      this.viewImg = false;
      this.setState({
        controlsVisible: true
      });
    }
  };

  onFocusArrow = () => {
    this.setState({
      forceVisibleArrows: true
    });
  };

  onBlurArrow = () => {
    this.setState({
      forceVisibleArrows: false
    });
  };

  triggerImageClick() {
    this.refs.content.triggerImageClick();
  }

  get subCheckForAutoPlay() {
    const { soundPlayer } = this.refs;

    return (
      !this.state.visiblePreviewImage && (!soundPlayer || (soundPlayer && !soundPlayer.playing))
    );
  }

  get contentComponent() {
    return this.refs.content;
  }

  get frameComponent() {
    return this.refs.frame;
  }

  get content() {
    return (
      <Frame title="slide" className={styles.content} tabIndex="0" ref="frame">
        <CardContent
          ref="content"
          card={this.props.currentCard}
          onClick={isMobile ? this.onClick : null}
          onImageClick={this.onImageClick}
          imageStyle={
            this.props.fullscreen || isMobile ? { pointerEvents: "none" } : { cursor: "zoom-in" }
          }
        />
      </Frame>
    );
  }

  get arrows() {
    const { onLeftArrowClick, onRightArrowClick } = this.props;
    const { controlsVisible, forceVisibleArrows } = this.state;

    return (
      <>
        <div
          className={classNames(
            styles.arrow,
            styles["arrow-left"],
            !controlsVisible && !forceVisibleArrows && Classes.HIDDEN
          )}
        >
          <Button
            id={Buttons.PREV}
            className={buttonStyles.prev}
            onClick={onLeftArrowClick}
            place="right"
            onFocus={this.onFocusArrow}
            onBlur={this.onBlurArrow}
            hint={true}
          />
        </div>
        <div
          className={classNames(
            styles.arrow,
            styles["arrow-right"],
            !controlsVisible && !forceVisibleArrows && Classes.HIDDEN
          )}
        >
          <Button
            id={Buttons.NEXT}
            className={buttonStyles.next}
            onClick={onRightArrowClick}
            onFocus={this.onFocusArrow}
            onBlur={this.onBlurArrow}
            place="left"
            hint={true}
          />
        </div>
      </>
    );
  }

  render() {
    const {
      animationClass,
      currentCard: { sound },
      stopAutoSlideshow,
      startAutoSlideshow,
      unlockNavControls,
      lockNavControls
    } = this.props;

    return (
      <div
        className={classNames(styles.container, animationClass)}
        onMouseEnter={!isMobile ? this.onCardMouseEnter : null}
        onMouseLeave={!isMobile ? this.onCardMouseLeave : null}
        onMouseMove={!isMobile ? this.onCardMouseMove : null}
        onClick={!isMobile ? this.onClick : null}
      >
        {this.content}
        {this.arrows}
        {Boolean(sound) && (
          <SoundPlayer
            ref="soundPlayer"
            visible={this.state.controlsVisible}
            src={sound}
            startAutoSlideshow={startAutoSlideshow}
            stopAutoSlideshow={stopAutoSlideshow}
            unlockNavControls={unlockNavControls}
            lockNavControls={lockNavControls}
            onToggleClick={this.onClick}
          />
        )}
      </div>
    );
  }
}
