import styles from "./Activity.module.scss";
import React, { Component } from "react";
import PropTypes from "prop-types";
import classNames from "classnames";
import { connect } from "react-redux";
import Hammer from "hammerjs";
import Fullscreen from "react-full-screen";
import buildActions from "../../../store/actions";
import actionTypes from "../../../store/types";
import {
  isMobile,
  isSafari,
  isPhonePortrait,
  isIE,
  isMSBrowser,
  isFirefox
} from "../../../../../../common/constants/user-agent";
import { Key } from "../../../../../../common/constants/keyboard";
import { Animations } from "../../../../../../common/constants/animations";
import Modal from "../../../../common/components/Modal/Modal";
import ShortcutsButton from "../../../../common/components/ShortcutsButton/ShortcutsButton";
import Button, { buttonStyles } from "../../../../common/components/Button/Button";
import { Buttons } from "../../../../../constants/buttons";
import { Classes } from "../../../../../../common/constants/classes";
import AdaHelper from "../../../../common/components/AdaHelper/AdaHelper";
import ActivityHeader from "../../../../common/components/ActivityHeader/ActivityHeader";
import ProgressBar from "../ProgressBar/ProgressBar";
import Card from "../Card/Card";
import { trapTabKey } from "../../../../../utils/accessibility";

@connect(
  state => ({
    cards: state.cards,
    autoPlaySpeed: state.autoPlaySpeed,
    currentCardIndex: state.currentCardIndex,
    cardsCount: state.cardsCount,
    activityName: state.name,
    nextAnimation: state.nextAnimation,
    prevAnimation: state.prevAnimation,
    studentInstruction: state.studentInstruction
  }),
  buildActions
)
class Activity extends Component {
  static widthToHeightRatio = 0.6;

  static propTypes = {
    cards: PropTypes.array.isRequired,
    autoPlaySpeed: PropTypes.number,
    currentCardIndex: PropTypes.number.isRequired,
    cardsCount: PropTypes.number.isRequired,
    activityName: PropTypes.string.isRequired,
    nextAnimation: PropTypes.string.isRequired,
    prevAnimation: PropTypes.string.isRequired,
    studentInstruction: PropTypes.string.isRequired,
    activityAlign: PropTypes.object,
    showNextCard: PropTypes.func.isRequired,
    showPrevCard: PropTypes.func.isRequired
  };

  static defaultProps = {
    autoPlaySpeed: null
  };

  state = {
    playerHeight: 0,
    fullscreen: false,
    mobileText: false,
    animationClass: "",
    ariaText: "",
    actionType: "",
    activeElement: ""
  };

  lockedNavControls = false;
  cardContainer = null;
  cardShowTimer = null;
  touchManager;
  touchIframeManager;

  playerStyle = {
    ...this.props.activityAlign
  };

  componentDidMount() {
    this.initTouchHandlers();
    this.onResize();
    this.startAutoSlideshow();
    window.addEventListener("resize", this.onResize);
  }

  componentDidUpdate() {
    if (this.state.fullscreen) {
      document.addEventListener("keydown", this.onActivityKeyDown, false);
      this.frameDocument.addEventListener("keydown", this.onActivityKeyDown, false);
    } else {
      document.removeEventListener("keydown", this.onActivityKeyDown, false);
      this.frameDocument.removeEventListener("keydown", this.onActivityKeyDown, false);
    }
  }

  componentWillUnmount() {
    this.removeTouchHandlers();
    this.stopAutoSlideshow();
    document.removeEventListener("keydown", this.onActivityKeyDown, false);
    this.frameDocument.removeEventListener("keydown", this.onActivityKeyDown, false);
    window.removeEventListener("resize", this.onResize);
  }

  showModal = (options, e) => {
    e.preventDefault();
    this.dialogModal.show(options);
  };

  onResize = () => {
    if (!this.state.fullscreen) this.updatePlayerHeight();
  };

  updatePlayerHeight(state = {}) {
    this.setState({
      ...state,
      playerHeight: isPhonePortrait()
        ? this.cardContainer.offsetWidth / Activity.widthToHeightRatio
        : this.cardContainer.offsetWidth * Activity.widthToHeightRatio
    });
  }

  initTouchHandlers = () => {
    if (isMobile) {
      const iframeBody = this.frameDocument.body;

      this.touchManager = new Hammer.Manager(this.cardContainer, {
        recognizers: [
          [Hammer.Swipe, { direction: Hammer.DIRECTION_HORIZONTAL }],
          [Hammer.Tap, { taps: 2 }]
        ]
      });

      this.touchIframeManager = new Hammer.Manager(iframeBody, {
        recognizers: [
          [Hammer.Swipe, { direction: Hammer.DIRECTION_HORIZONTAL }],
          [Hammer.Tap, { taps: 2 }]
        ]
      });

      this.touchManager.on("swipeleft", this.showNextCard);
      this.touchManager.on("swiperight", this.showPrevCard);
      this.touchIframeManager.on("swipeleft", this.showNextCard);
      this.touchIframeManager.on("swiperight", this.showPrevCard);
    }
  };

  removeTouchHandlers = () => {
    if (isMobile) {
      this.touchManager.off("swipeleft");
      this.touchManager.off("swiperight");
      this.touchManager.destroy();
      this.touchIframeManager.off("swipeleft");
      this.touchIframeManager.off("swiperight");
      this.touchIframeManager.destroy();
    }
  };

  onMoveAnimationEnd = () => {
    const { currentCardIndex, cardsCount } = this.props;
    let ariaText = "";

    switch (this.state.actionType) {
      case actionTypes.SHOW_PREV_CARD:
      case actionTypes.SHOW_NEXT_CARD:
        ariaText = `Slide ${currentCardIndex + 1} of ${cardsCount}.`;
        break;
      default:
    }

    this.setState({
      animationClass: "",
      actionType: "",
      activeElement: "",
      ariaText
    });
  };

  onActivityKeyDown = e => {
    switch (e.keyCode) {
      case Key.NUMPAD_ADD:
        if (e.altKey) {
          e.preventDefault();
          this.refs.card.triggerImageClick();
        }
        break;
      case Key.LEFT:
        e.preventDefault();
        this.showPrevCard();
        break;
      case Key.RIGHT:
        e.preventDefault();
        this.showNextCard();
        break;
      case Key.ESC:
        if (this.state.fullscreen) {
          e.preventDefault();
          this.disableFullscreen();
        }
        break;
      case Key.F:
        if (e.altKey && !isMSBrowser) {
          e.preventDefault();
          this.toggleFullscreen();
        }
        break;

      case Key.TAB:
        if (this.state.fullscreen && isFirefox) {
          trapTabKey(e);
        }
        break;
      default:
    }
  };

  onSoundEnd = () => {
    this.showNextCard();
  };

  onLeftArrowClick = () => {
    this.showPrevCard();
  };

  onRightArrowClick = () => {
    this.showNextCard();
  };

  showNextCard = () => {
    if (this.animationFinished && !this.lockedNavControls && !this.isSliderInFocus) {
      const { nextAnimation, showNextCard } = this.props;

      this.stopAutoSlideshow();
      this.setState({
        animationClass: Animations[nextAnimation] || "",
        ariaText: "",
        actionType: actionTypes.SHOW_NEXT_CARD
      });

      showNextCard();
      this.startAutoSlideshow();
    }
  };

  showPrevCard = () => {
    if (this.animationFinished && !this.lockedNavControls && !this.isSliderInFocus) {
      const { prevAnimation, showPrevCard } = this.props;
      this.stopAutoSlideshow();
      this.setState({
        animationClass: Animations[prevAnimation] || "",
        ariaText: "",
        actionType: actionTypes.SHOW_PREV_CARD
      });
      showPrevCard();
      this.startAutoSlideshow();
    }
  };

  lockNavControls = () => {
    this.stopAutoSlideshow();
    this.lockedNavControls = true;
  };

  unlockNavControls = () => {
    this.stopAutoSlideshow();
    this.lockedNavControls = false;
    this.startAutoSlideshow();
  };

  startAutoSlideshow = () => {
    const { autoPlaySpeed } = this.props;

    if (
      autoPlaySpeed &&
      !this.cardShowTimer &&
      this.refs.card &&
      this.refs.card.subCheckForAutoPlay
    ) {
      this.cardShowTimer = setInterval(this.showNextCard, autoPlaySpeed * 1000);
    }
  };

  stopAutoSlideshow = () => {
    clearTimeout(this.cardShowTimer);
    this.cardShowTimer = null;
  };

  toggleShowText = () => {
    this.setState({
      mobileText: !this.state.mobileText
    });
  };

  onChangeFullscreen = fullscreen => {
    this.updatePlayerHeight({ fullscreen });
    this.cardContentComponent.updateImageSize();

    // hack for safari in lesson
    if (isSafari) {
      if (fullscreen) {
        document.body.style.visibility = "hidden";
      } else {
        document.body.style.removeProperty("visibility");
      }
    }
  };

  enableFullscreen = () => {
    this.setState({ fullscreen: true });
  };

  disableFullscreen = () => {
    this.setState({ fullscreen: false });
  };

  toggleFullscreen = () => {
    this.setState({ fullscreen: !this.state.fullscreen });
  };

  get isSliderInFocus() {
    return document.activeElement && document.activeElement.getAttribute("role") === "slider";
  }

  get cardContentComponent() {
    return this.refs.card.contentComponent;
  }

  get frameDocument() {
    return this.refs.card.frameComponent.document;
  }

  get animationFinished() {
    return !this.state.animationClass;
  }

  get dialogModalBlock() {
    return <Modal ref={element => (this.dialogModal = element)} />;
  }

  get navigationButton() {
    return (
      <ShortcutsButton
        className={isMobile && Classes.NOT_VISIBLE}
        listPosition="top"
        excludeItems={{ fullscreen: isMSBrowser }}
      />
    );
  }

  get fullscreenButton() {
    return (
      <Button
        ref="fullscreen"
        id={Buttons.FULLSCREEN}
        className={classNames(buttonStyles[Buttons.FULLSCREEN], isMobile && Classes.NOT_VISIBLE)}
        onClick={this.enableFullscreen}
        disableAccessibility={isIE}
        hint={true}
      />
    );
  }

  get player() {
    const { playerHeight: height, fullscreen, mobileText } = this.state;
    const { cards, currentCardIndex, cardsCount } = this.props;
    const playerStyle = Object.assign({ height }, this.activityAlign);

    return (
      <div
        role="application"
        ref={element => (this.cardContainer = element)}
        style={playerStyle}
        className={styles.player}
        onAnimationEnd={this.onMoveAnimationEnd}
      >
        <Fullscreen enabled={fullscreen} onChange={this.onChangeFullscreen}>
          <Card
            ref="card"
            animationClass={this.state.animationClass}
            fullscreen={fullscreen}
            mobileText={mobileText}
            currentCard={cards[currentCardIndex]}
            stopAutoSlideshow={this.stopAutoSlideshow}
            startAutoSlideshow={this.startAutoSlideshow}
            lockNavControls={this.lockNavControls}
            unlockNavControls={this.unlockNavControls}
            onLeftArrowClick={this.onLeftArrowClick}
            onRightArrowClick={this.onRightArrowClick}
            showModal={this.showModal}
          />
        </Fullscreen>
        <div className={styles.footer}>
          {this.navigationButton}
          <ProgressBar totalCount={cardsCount} currentCount={currentCardIndex + 1} />
          {this.fullscreenButton}
        </div>
      </div>
    );
  }

  render() {
    return (
      <section tabIndex="0" className={styles.container} onKeyDown={this.onActivityKeyDown}>
        <AdaHelper ariaText={this.state.ariaText} />
        <ActivityHeader
          activityName={this.props.activityName}
          studentInstruction={this.props.studentInstruction}
        />
        {this.dialogModalBlock}
        {this.player}
      </section>
    );
  }
}

export default Activity;
