import "rc-slider/assets/index.css";
import styles from "./SoundControl.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import Slider from "rc-slider";
import { Buttons } from "../../../../../constants/buttons";
import Button, { buttonStyles } from "../../../../common/components/Button/Button";
import { InjectLocale } from "../../../../../decorators/locale";

@InjectLocale("SoundControl")
class SoundControl extends PureComponent {
  static defaultProps = {
    max: 100,
    step: 1
  };

  static propTypes = {
    type: PropTypes.string.isRequired,
    value: PropTypes.number.isRequired,
    onChange: PropTypes.func.isRequired,
    onFocus: PropTypes.func.isRequired,
    onBlur: PropTypes.func.isRequired,
    max: PropTypes.number,
    step: PropTypes.number,
    lockNavControls: PropTypes.func.isRequired,
    unlockNavControls: PropTypes.func.isRequired,
    ariaValueText: PropTypes.string.isRequired
  };

  state = {
    showSlider: false
  };

  toggleSlider = () => {
    this.setState({
      showSlider: !this.state.showSlider
    });
  };

  setValueTextAttrRef = el => {
    if (el) {
      let sliderHandle = el.sliderRef && el.sliderRef.querySelector('[role="slider"]');
      if (sliderHandle) {
        sliderHandle.setAttribute("aria-label", this.locale[this.props.ariaValueText]);
      }
    }
  };

  render() {
    const {
      onChange,
      onFocus,
      onBlur,
      type,
      value,
      max,
      lockNavControls,
      unlockNavControls,
      step
    } = this.props;
    const id = Buttons[type.toUpperCase()];

    return (
      <div className={styles.container}>
        <Button
          id={id}
          className={buttonStyles[id.split("_").join("-")]}
          onClick={this.toggleSlider}
          onFocus={onFocus}
          onBlur={onBlur}
          ariaPressed={this.state.showSlider}
        />
        {this.state.showSlider && (
          <Slider
            ref={this.setValueTextAttrRef}
            min={0}
            max={max}
            step={step}
            value={value}
            dots={false}
            style={{
              width: "80%",
              margin: "0 auto"
            }}
            trackStyle={{
              backgroundColor: "white"
            }}
            railStyle={{
              backgroundColor: "rgba(200, 200, 200, 0.6)"
            }}
            onFocus={onFocus}
            onBlur={onBlur}
            onChange={onChange}
            onBeforeChange={lockNavControls}
            onAfterChange={unlockNavControls}
          />
        )}
      </div>
    );
  }
}

export default SoundControl;
