import styles from "../../../styles/utils/_variables.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import { sleep } from "../../utils/async";
import { URLManager } from "../../utils/url";
import { Slideshow } from "../../constants/activities/slideshow";

const updateImageSize = Symbol("@@update_image_size");

export default class CardContent extends PureComponent {
  static imageMap = new Map();

  static defaultProps = {
    style: {
      position: "relative",
      width: "100%",
      height: "100%"
    },
    imageStyle: {}
  };

  static propTypes = {
    card: PropTypes.object.isRequired,
    hideContent: PropTypes.bool,
    onImageClick: PropTypes.func,
    onClick: PropTypes.func,
    style: PropTypes.object,
    imageStyle: PropTypes.object,
    className: PropTypes.string
  };

  state = {
    imageStyle: { opacity: 0 }
  };

  queueToUpdateTheImage = Promise.resolve();

  contentInnerStyle = {
    width: "100%"
  };

  static getPositionStyles(position) {
    const style = { position: "absolute" };

    switch (position) {
      case Slideshow.POSITIONS.none:
        style.display = "none";
        break;
      case Slideshow.POSITIONS.center:
        Object.assign(style, {
          width: "75%",
          height: "75%",
          left: "50%",
          top: "50%",
          transform: "translate(-50%, -50%)"
        });
        break;
      case Slideshow.POSITIONS.bottom:
        Object.assign(style, {
          width: "100%",
          height: "50%",
          left: "0",
          bottom: "0"
        });
        break;
      case Slideshow.POSITIONS.top:
        Object.assign(style, {
          width: "100%",
          height: "50%",
          left: "0",
          top: "0"
        });
        break;
      case Slideshow.POSITIONS.left:
        Object.assign(style, {
          width: "50%",
          height: "100%",
          left: "0",
          top: "0"
        });
        break;
      case Slideshow.POSITIONS.right:
        Object.assign(style, {
          width: "50%",
          height: "100%",
          right: "0",
          top: "0"
        });
        break;
      case Slideshow.POSITIONS.fill:
        Object.assign(style, {
          width: "100%",
          height: "100%",
          left: "0",
          top: "0"
        });
        break;
      default:
    }

    return style;
  }

  componentDidMount() {
    this.resizeContent();
    window.addEventListener("resize", this.resizeContent);
  }

  componentWillReceiveProps(props) {
    if (this.props.card && props.card && this.props.card.image !== props.card.image) {
      this.resetImageStyle();
    }
  }

  componentDidUpdate(prevProps) {
    const { card } = this.props;
    const { card: prevCard } = prevProps;

    if (
      card &&
      prevCard &&
      card.image &&
      (card.templateIndex !== prevCard.templateIndex || card.imageFit !== prevCard.imageFit)
    ) {
      this.updateImageSize();
    }

    this.resizeContent();
  }

  componentWillUnmount() {
    window.removeEventListener("resize", this.resizeContent);
  }

  triggerImageClick() {
    this.refs.image.click();
  }

  get template() {
    return Slideshow.TEMPLATES[this.props.card.templateIndex];
  }

  get containerStyle() {
    return {
      overflow: "hidden",
      ...this.props.style
    };
  }

  get contentStyle() {
    const { verticalAlign } = this.props.card;
    const template = this.template;

    return {
      position: "relative",
      display: this.props.hideContent ? "none" : "flex",
      ...CardContent.getPositionStyles(template.content),
      ...((template.overlay && { background: Slideshow.COLORS.contentOverlayBackground }) || {}),
      alignItems:
        verticalAlign === Slideshow.POSITIONS.center
          ? "center"
          : verticalAlign === Slideshow.POSITIONS.bottom
          ? "flex-end"
          : "flex-start",
      overflow: "hidden",
      wordBreak: "break-word",
      boxSizing: "border-box",
      padding: "5%"
    };
  }

  get backgroundWrapperStyle() {
    const template = this.template;

    return {
      display: "flex",
      ...CardContent.getPositionStyles(template.image),
      alignItems: "center",
      justifyContent: "center",
      overflow: "hidden",
      backgroundColor: this.props.card.backgroundColor
    };
  }

  get imageStyle() {
    return {
      MozUserSelect: "none",
      WebkitUserSelect: "none",
      msUserSelect: "none",
      ...this.state.imageStyle,
      ...this.props.imageStyle
    };
  }

  onImageClick = e => {
    const { onImageClick } = this.props;
    if (onImageClick) onImageClick(e);
  };

  updateImageStyle(imageStyle) {
    return new Promise(resolve => this.setState({ imageStyle }, resolve));
  }

  resetImageStyle() {
    return this.updateImageStyle({ opacity: 0 });
  }

  updateImageSize = () => {
    this.queueToUpdateTheImage = this.queueToUpdateTheImage.then(() => this[updateImageSize]());
  };

  async [updateImageSize]() {
    const { image } = this.refs;

    if (image) {
      await this.resetImageStyle();
      await sleep(16);

      if (this.props.card.imageFit === Slideshow.IMAGE_FIT.cover) {
        const imageWrapper = image.parentNode;
        const ratioImage = image.offsetWidth / image.offsetHeight;
        const ratioImageWrapper = imageWrapper.offsetWidth / imageWrapper.offsetHeight;

        if (ratioImage > ratioImageWrapper) {
          await this.updateImageStyle({ height: "100%" });
        } else {
          await this.updateImageStyle({ width: "100%" });
        }
      } else {
        await this.updateImageStyle({
          maxWidth: "100%",
          maxHeight: "100%"
        });
      }
    }
  }

  resizeContent = () =>
    requestAnimationFrame(() => {
      const { container, content } = this.refs;

      if (container && content) {
        const scaleFactor = container.offsetWidth / parseInt(styles.cardContentWidth);

        if (scaleFactor < 1) {
          content.style.fontSize = `${scaleFactor}em`;
        } else {
          content.style.removeProperty("font-size");
        }
      }
    });

  render() {
    const { card, onClick, className } = this.props;

    return card ? (
      <div
        id="container"
        style={this.containerStyle}
        onClick={onClick}
        className={className}
        ref="container"
      >
        <div id="background" style={this.backgroundWrapperStyle}>
          {card.image && (
            <img
              ref="image"
              src={URLManager.getContentUrl(card.image, true)}
              alt={card.altText}
              style={this.imageStyle}
              onLoad={this.updateImageSize}
              onClick={this.onImageClick}
            />
          )}
        </div>
        <div ref="content" id="content" style={this.contentStyle}>
          <div dangerouslySetInnerHTML={{ __html: card.content }} style={this.contentInnerStyle} />
        </div>
      </div>
    ) : null;
  }
}
